const campaign = items[0].json;
if (!campaign || !campaign.id) {
  return [{ json: { ok: false, error: 'No draft campaign found', skip: true } }];
}
const audience = campaign.target_audience || {};
const missing = [];
if (!campaign.brief || String(campaign.brief).trim().length < 20) missing.push('brief');
if (!campaign.product_type) missing.push('product_type');
const geos = audience.geographies || audience.geography || audience.countries;
if (!geos || (Array.isArray(geos) && geos.length === 0)) missing.push('target_audience.geographies');
const hasAge = audience.age_min != null || audience.age_max != null || audience.age_range || audience.description;
if (!hasAge) missing.push('target_audience.age_range_or_description');

return [{
  json: {
    ok: missing.length === 0,
    missing_fields: missing,
    message: missing.length ? `Missing critical fields: ${missing.join(', ')}. Do not invent values.` : null,
    campaign
  }
}];

